    seo: { title: 'SEO Optimalizace', tagline: 'Organický růst. Dlouhodobé výsledky.', heroTagline: 'Strana 1. Dlouhodobě.', desc: 'Komplexní SEO strategie, která vás dostane na první pozice ve vyhledávačích.', overview: 'Komplexní SEO strategie, která vás dostane na první pozice ve vyhledávačích. Technické SEO, keyword analýza, contenthub a link building v jednom balíku.', process: [{ step: '01', title: 'SEO Audit', desc: 'Kompletní analýza technického stavu, obsahové strategie a profilu zpětných odkazů.' }, { step: '02', title: 'Keyword Research', desc: 'Mapování keyword příležitostí, analýza search intent a prioritizace podle business impaktu.' }, { step: '03', title: 'Technical SEO', desc: 'Oprava technických chyb, Core Web Vitals, structured data, crawlability a indexace.' }, { step: '04', title: 'Content Strategy', desc: 'Contenthub architektura, topic clustering a redakční kalendář pro dlouhodobý organický růst.' }, { step: '05', title: 'Link Building', desc: 'White-hat link building přes digital PR, guest posting a partnership. Žádné black-hat taktiky.' }], benefits: ['Měřitelné výsledky každý měsíc', 'Transparentní reporting', 'Technical & content SEO', 'Local SEO pokud potřebujete', 'E-E-A-T optimalizace', 'Schema markup'], faq: [{ q: 'Kdy uvidím výsledky SEO?', a: 'První pohyby rankingů vidíme po 6–8 týdnech. Significant traffic nárůst po 4–6 měsících. SEO je maraton.' }, { q: 'Děláte lokální SEO?', a: 'Ano. Google Business Profile optimalizace, lokální citace a lokální keyword strategie.' }, { q: 'Zahrnuje SEO tvorbu obsahu?', a: 'Podle balíku. Umíme zajistit kompletní SEO copywriting nebo jen strategii a guidelines.' }] },
