    'social-media': { title: 'Social Media Management', tagline: 'Komunita, která nakupuje.', heroTagline: 'Sociální sítě, které prodávají.', desc: 'Správa sociálních sítí od A do Z — contentstrategie, tvorba příspěvků, community management a analytika.', overview: 'Správa sociálních sítí od A do Z — contentstrategie, tvorba příspěvků, community management a analytika. Vaše sociální sítě budou žít a konvertovat.', process: [{ step: '01', title: 'Social Audit', desc: 'Analýza existujících profilů, competitor benchmarking a identifikace příležitostí.' }, { step: '02', title: 'Content Strategy', desc: 'Content pillars, tone of voice, editoriální kalendář a vizuální styl pro každou platformu.' }, { step: '03', title: 'Content Creation', desc: 'Měsíční batch příspěvků — fotografie, grafiky, reels, stories. Vše v jednom balíku.' }, { step: '04', title: 'Publishing & Community', desc: 'Plánovaný publishing, community management, odpovědi na komentáře a DMs.' }, { step: '05', title: 'Analytics & Reporting', desc: 'Měsíční reporty s growth metrics, engagement rate a content performance analýzou.' }], benefits: ['Konzistentní přítomnost', 'Originální content každý měsíc', 'Community management', 'Instagram · Facebook · LinkedIn · TikTok', 'Kolaborace a UGC', 'Měsíční reporty'], faq: [{ q: 'Kolik příspěvků měsíčně dostaneme?', a: 'Závisí od balíku — od 12 do 30 příspěvků měsíčně + stories. Editoriální kalendář schvalujete předem.' }, { q: 'Kdo tvoří obsah?', a: 'Náš in-house content tým — grafici, copywriteři a videografové. Focení zajišťujeme podle dohody.' }, { q: 'Můžeme zasahovat do obsahu?', a: 'Samozřejmě. Před publishingem vždy dostanete obsah ke schválení.' }] },
    '3d-motion': { title: '3D Vizuály & Motion Design', tagline: 'Pohyblivé obrazy, které prodávají.', heroTagline: 'Vizuály z jiného světa.', desc: 'Vytváříme 3D vizualizace, motion graphics a animace pro reklamy, produkty a prezentace.', overview: 'Vytváříme 3D vizualizace, motion graphics a animace pro reklamy, produkty a prezentace. Každý vizuál je precizně navržen pro maximální dojem.', process: [{ step: '01', title: 'Brief', desc: 'Definujeme vizuální směr, styl a technické požadavky.' }, { step: '02', title: 'Concept', desc: 'Vytváříme moodboard a konceptuální návrhy ke schválení.' }, { step: '03', title: 'Production', desc: '3D modelování, texturing, rigging a animace na nejvyšší úrovni.' }, { step: '04', title: 'Render', desc: 'High-quality rendering a compositing s post-produkcí.' }, { step: '05', title: 'Delivery', desc: 'Export ve všech potřebných formátech a rozlišeních.' }], benefits: ['Fotorealistické vizuály', 'Produktová vizualizace', 'Animované reklamy', 'Explainer videos', 'Brand animations', 'VFX integrace'], faq: [{ q: 'Jak dlouho trvá 3D projekt?', a: 'Závisí na komplexnosti. Jednoduchá animace 5–7 dní, složitá 3D scéna 2–4 týdny.' }, { q: 'Jaké formáty dodáváte?', a: 'MP4, MOV, GIF, PNG sekvence — vše dle potřeb klienta.' }, { q: 'Děláte produktové vizualizace?', a: 'Ano. Fotorealistické 3D produktové vizuály jsou naše silná stránka.' }] },
    'digital-strategy': { title: 'Digitální Strategie', tagline: 'Plán, který vede k výsledkům.', heroTagline: 'Strategie na míru.', desc: 'Navrhujeme komplexní digitální strategie pro růst vašeho podnikání. Od audit analýzy po roadmap implementaci.', overview: 'Navrhujeme komplexní digitální strategie pro růst vašeho podnikání. Od audit analýzy po roadmap implementaci — s důrazem na měřitelné výsledky a ROI.', process: [{ step: '01', title: 'Audit', desc: 'Kompletní analýza aktuálního stavu digitální přítomnosti a konkurence.' }, { step: '02', title: 'Goals', desc: 'Definice KPIs, cílů a měřitelných výsledků pro každý kanál.' }, { step: '03', title: 'Strategy', desc: 'Tvorba komplexní multi-channel strategie šité na míru.' }, { step: '04', title: 'Roadmap', desc: 'Detailní akční plán s časovým harmonogramem.' }, { step: '05', title: 'Review', desc: 'Pravidelné review a optimalizace strategie podle výsledků.' }], benefits: ['360° digitální pohled', 'Data-driven rozhodnutí', 'Multi-channel plán', 'Konkurenční analýza', 'Měřitelné KPIs', 'Kvartální reviewy'], faq: [{ q: 'Co zahrnuje digitální strategie?', a: 'Audit, analýzu konkurence, definici cílů, multi-channel plán a roadmap implementace.' }, { q: 'Jak dlouho trvá vypracování strategie?', a: 'Základní strategie 2–3 týdny. Komplexní s hloubkovou analýzou 4–6 týdnů.' }, { q: 'Implementujete strategii také vy?', a: 'Ano. Umíme strategii nejen navrhnout, ale také plnohodnotně implementovat přes naše další služby.' }] },
